// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Regression test for FILTER(bound(?x)) / FILTER(!bound(?x)) over variables bound by statement patterns in the native
 * LMDB query engine.
 */
public class LmdbNativeQueryBoundFilterTest {

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			conn.add(vf.createIRI("http://example.com/s1"), vf.createIRI("http://example.com/p"),
					vf.createLiteral("a"));
			conn.add(vf.createIRI("http://example.com/s2"), vf.createIRI("http://example.com/p"),
					vf.createLiteral("b"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void boundFilterOnPatternVariableKeepsAllSolutions() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn
					.prepareTupleQuery("SELECT ?x WHERE { ?x ?p ?o FILTER(bound(?x)) }")
					.evaluate());
			assertThat(result).hasSize(2);
		}
	}

	@Test
	public void notBoundFilterOnPatternVariableRemovesAllSolutions() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn
					.prepareTupleQuery("SELECT ?x WHERE { ?x ?p ?o FILTER(!bound(?x)) }")
					.evaluate());
			assertThat(result).isEmpty();
		}
	}

	@Test
	public void boundFilterInDisjunctionIsPlacedAtBindingDepth() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn
					.prepareTupleQuery("SELECT ?x WHERE { ?x ?p ?o FILTER(bound(?x) || ?o = \"missing\") }")
					.evaluate());
			assertThat(result).hasSize(2);
		}
	}
}
